     1→import { useState, useCallback, useRef, useLayoutEffect, useEffect } from "react";
     2→import ReactMarkdown from "react-markdown";
     3→import type { DisplayMessage, DisplayItem } from "../types";
     4→import { shortModel, formatTokens, formatDuration, formatExactTime } from "../lib/format";
     5→import { getModelColor, getTeamColor } from "../lib/theme";
     6→import { MessageItem } from "./MessageItem";
     7→import { DetailItem } from "./DetailItem";
     8→import { useToggleSet } from "../hooks/useToggleSet";
     9→import { useScrollToSelected } from "../hooks/useScrollToSelected";
    10→import { useAutoScroll } from "../hooks/useAutoScroll";
    11→import { useKeyboard } from "../hooks/useKeyboard";
    12→import { useRegisterViewActions, type ViewActionsRef } from "../hooks/useViewActions";
    13→import { BackButton } from "./BackButton";
    14→import { ResizeHandle } from "./ResizeHandle";
    15→import { OngoingDots } from "./OngoingDots";
    16→import { IoMdCloseCircle } from "react-icons/io";
    17→import { ClaudeIcon } from "./Icons";
    18→
    19→/* ─── Helpers ─── */
    20→
    21→/** Recursively find a DisplayItem by agent_id in a nested item tree. */
    22→function findItemByAgentId(items: DisplayItem[], agentId: string): DisplayItem | undefined {
    23→  for (const item of items) {
    24→    if (item.agent_id === agentId) return item;
    25→    for (const subMsg of item.subagent_messages) {
    26→      const found = findItemByAgentId(subMsg.items, agentId);
    27→      if (found) return found;
    28→    }
    29→  }
    30→  return undefined;
    31→}
    32→
    33→/* ─── Panel stack types ─── */
    34→
    35→type PanelEntry =
    36→  | { kind: "agent-list"; item: DisplayItem; key: string }
    37→  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
    38→
    39→/** Imperative handle exposed by each navigable column */
    40→interface ColumnNav {
    41→  moveUp: () => void;
    42→  moveDown: () => void;
    43→  toggle: () => void;
    44→  enter: () => void;
    45→  itemCount: () => number;
    46→  expandAll: () => void;
    47→  collapseAll: () => void;
    48→}
    49→
    50→interface MessageDetailProps {
    51→  message: DisplayMessage;
    52→  ongoing?: boolean;
    53→  onBack: () => void;
    54→  viewActionsRef: ViewActionsRef;
    55→}
    56→
    57→export function MessageDetail({
    58→  message: msg,
    59→  ongoing,
    60→  onBack,
    61→  viewActionsRef,
    62→}: MessageDetailProps) {
    63→  const {
    64→    set: expandedItems,
    65→    toggle: toggleItem,
    66→    addAll: expandAllItems,
    67→    clear: clearItems,
    68→  } = useToggleSet();
    69→  const [selectedItem, setSelectedItem] = useState(0);
    70→  const scrollRef = useScrollToSelected(selectedItem);
    71→  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
    72→  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
    73→  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
    74→  const bodyRef = useRef<HTMLDivElement>(null);
    75→  useAutoScroll(msg.items.length, bodyRef);
    76→  const savedScroll = useRef<number | null>(null);
    77→  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
    78→
    79→  const detailExpandAll = useCallback(() => {
    80→    if (focusedColumn === 0) {
    81→      expandAllItems(msg.items.map((_, i) => i));
    82→    } else {
    83→      panelRefs.current.get(focusedColumn - 1)?.expandAll();
    84→    }
    85→  }, [msg.items, expandAllItems, focusedColumn]);
    86→
    87→  const detailCollapseAll = useCallback(() => {
    88→    if (focusedColumn === 0) {
    89→      clearItems();
    90→    } else {
    91→      panelRefs.current.get(focusedColumn - 1)?.collapseAll();
    92→    }
    93→  }, [clearItems, focusedColumn]);
    94→
    95→  useRegisterViewActions(viewActionsRef, {
    96→    expandAll: detailExpandAll,
    97→    collapseAll: detailCollapseAll,
    98→  });
    99→
   100→  // Keep panel stack items fresh when the session watcher sends updated data.
   101→  // Without this, subagent_ongoing and subagent_messages would be stale.
   102→  // Only updates state when something meaningful changed to avoid extra re-renders.
   103→  useEffect(() => {
   104→    if (panelStack.length === 0) return;
   105→    setPanelStack((prev) => {
   106→      let changed = false;
   107→      const next = prev.map((entry) => {
   108→        if (!entry.item.agent_id) return entry;
   109→        const fresh = findItemByAgentId(msg.items, entry.item.agent_id);
   110→        if (!fresh) return entry;
   111→        // Skip if nothing meaningful changed.
   112→        if (
   113→          fresh.subagent_ongoing === entry.item.subagent_ongoing &&
   114→          fresh.subagent_messages.length === entry.item.subagent_messages.length
   115→        ) {
   116→          return entry;
   117→        }
   118→        changed = true;
   119→        if (entry.kind === "agent-list") {
   120→          return { ...entry, item: fresh };
   121→        }
   122→        // For agent-detail, also refresh the message by matching timestamp.
   123→        const freshMsg =
   124→          fresh.subagent_messages.find(
   125→            (m) => m.timestamp === entry.msg.timestamp && m.role === entry.msg.role,
   126→          ) ?? entry.msg;
   127→        return { ...entry, item: fresh, msg: freshMsg };
   128→      });
   129→      return changed ? next : prev;
   130→    });
   131→  }, [msg.items, panelStack.length]);
   132→
   133→  useLayoutEffect(() => {
   134→    if (savedScroll.current != null && bodyRef.current) {
   135→      bodyRef.current.scrollTop = savedScroll.current;
   136→      savedScroll.current = null;
   137→    }
   138→  }, [panelStack.length]);
   139→
   140→  const model = msg.model ? shortModel(msg.model) : "";
   141→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
   142→  const time = formatExactTime(msg.timestamp);
   143→  const hasItems = msg.items.length > 0;
   144→  const hasPanels = panelStack.length > 0;
   145→
   146→  // Stack manipulation
   147→  const openSubagentFromMain = useCallback((item: DisplayItem) => {
   148→    if (bodyRef.current) {
   149→      savedScroll.current = bodyRef.current.scrollTop;
   150→    }
   151→    let closed = false;
   152→    setPanelStack((prev) => {
   153→      if (
   154→        prev.length === 1 &&
   155→        prev[0].kind === "agent-list" &&
   156→        prev[0].item.agent_id === item.agent_id
   157→      ) {
   158→        closed = true;
   159→        return [];
   160→      }
   161→      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
   162→    });
   163→    setColumnWidths((prev) => [prev[0]]);
   164→    setFocusedColumn(closed ? 0 : 1);
   165→  }, []);
   166→
   167→  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
   168→    setPanelStack((prev) => {
   169→      const next = prev.slice(0, depth + 1);
   170→      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
   171→      return next;
   172→    });
   173→    setColumnWidths((prev) => prev.slice(0, depth + 2));
   174→    setFocusedColumn(depth + 2);
   175→  }, []);
   176→
   177→  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
   178→    setPanelStack((prev) => {
   179→      const entry = prev[depth];
   180→      if (!entry || entry.kind !== "agent-list") return prev;
   181→      const next = prev.slice(0, depth);
   182→      next.push({
   183→        kind: "agent-detail",
   184→        item: entry.item,
   185→        msg: detailMsg,
   186→        key: entry.key + ":detail",
   187→      });
   188→      return next;
   189→    });
   190→  }, []);
   191→
   192→  const backToListAt = useCallback((depth: number) => {
   193→    setPanelStack((prev) => {
   194→      const entry = prev[depth];
   195→      if (!entry || entry.kind !== "agent-detail") return prev;
   196→      const next = prev.slice(0, depth);
   197→      next.push({
   198→        kind: "agent-list",
   199→        item: entry.item,
   200→        key: entry.item.agent_id || `panel-${depth}`,
   201→      });
   202→      return next;
   203→    });
   204→  }, []);
   205→
   206→  const closeAt = useCallback((depth: number) => {
   207→    setPanelStack((prev) => prev.slice(0, depth));
   208→    setColumnWidths((prev) => prev.slice(0, depth + 1));
   209→    setFocusedColumn((prev) => Math.min(prev, depth));
   210→  }, []);
   211→
   212→  const setColumnWidth = useCallback((colIndex: number, width: number) => {
   213→    setColumnWidths((prev) => {
   214→      const next = [...prev];
   215→      while (next.length <= colIndex) next.push(null);
   216→      next[colIndex] = width;
   217→      return next;
   218→    });
   219→  }, []);
   220→
   221→  const handleItemClick = (index: number, item: DisplayItem) => {
   222→    setSelectedItem(index);
   223→    setFocusedColumn(0);
   224→    if (item.subagent_messages.length > 0) {
   225→      openSubagentFromMain(item);
   226→    } else {
   227→      toggleItem(index);
   228→    }
   229→  };
   230→
   231→  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
   232→    if (nav) {
   233→      panelRefs.current.set(depth, nav);
   234→    } else {
   235→      panelRefs.current.delete(depth);
   236→    }
   237→  }, []);
   238→
   239→  // Single keyboard handler for all columns
   240→  const detailKeyMap: Record<string, () => void> = {};
   241→
   242→  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
   243→  const moveDown = () => {
   244→    if (focusedColumn === 0) {
   245→      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
   246→    } else {
   247→      const nav = panelRefs.current.get(focusedColumn - 1);
   248→      nav?.moveDown();
   249→    }
   250→  };
   251→  const moveUp = () => {
   252→    if (focusedColumn === 0) {
   253→      setSelectedItem((i) => Math.max(i - 1, 0));
   254→    } else {
   255→      const nav = panelRefs.current.get(focusedColumn - 1);
   256→      nav?.moveUp();
   257→    }
   258→  };
   259→  detailKeyMap["j"] = moveDown;
   260→  detailKeyMap["ArrowDown"] = moveDown;
   261→  detailKeyMap["k"] = moveUp;
   262→  detailKeyMap["ArrowUp"] = moveUp;
   263→  detailKeyMap["Tab"] = () => {
   264→    if (focusedColumn === 0) {
   265→      const item = msg.items[selectedItem];
   266→      if (item) handleItemClick(selectedItem, item);
   267→    } else {
   268→      const nav = panelRefs.current.get(focusedColumn - 1);
   269→      nav?.toggle();
   270→    }
   271→  };
   272→  detailKeyMap["Enter"] = () => {
   273→    if (focusedColumn === 0) {
   274→      const item = msg.items[selectedItem];
   275→      if (item && item.subagent_messages.length > 0) {
   276→        openSubagentFromMain(item);
   277→      } else if (item) {
   278→        toggleItem(selectedItem);
   279→      }
   280→    } else {
   281→      const nav = panelRefs.current.get(focusedColumn - 1);
   282→      nav?.enter();
   283→    }
   284→  };
   285→
   286→  // h/l or ArrowLeft/ArrowRight to switch focused column
   287→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
   288→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
   289→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
   290→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
   291→
   292→  // q = go back to list
   293→  detailKeyMap["q"] = onBack;
   294→  // Escape = close rightmost panel, or go back
   295→  detailKeyMap["Escape"] = () => {
   296→    if (panelStack.length > 0) {
   297→      closeAt(panelStack.length - 1);
   298→    } else {
   299→      onBack();
   300→    }
   301→  };
   302→
   303→  useKeyboard(detailKeyMap);
   304→
   305→  const mainWidthStyle =
   306→    hasPanels && columnWidths[0]
   307→      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
   308→      : undefined;
   309→
   310→  return (
   311→    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
   312→      <div
   313→        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
   314→        style={mainWidthStyle}
   315→        onClick={() => setFocusedColumn(0)}
   316→      >
   317→        <div className="message-detail__header">
   318→          <BackButton onClick={onBack} />
   319→          <span className="message-detail__title">
   320→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
   321→          </span>
   322→          {model && (
   323→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
   324→          )}
   325→          {msg.subagent_label && (
   326→            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
   327→          )}
   328→          <span className="message-detail__meta">
   329→            {time}
   330→            {msg.tokens_raw > 0 && (
   331→              <>
   332→                {" "}
   333→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
   334→              </>
   335→            )}
   336→            {msg.duration_ms > 0 && (
   337→              <>
   338→                {" "}
   339→                {"\u00B7"} {formatDuration(msg.duration_ms)}
   340→              </>
   341→            )}
   342→          </span>
   343→        </div>
   344→
   345→        <div className="message-detail__body" ref={bodyRef}>
   346→          <div className="message-detail__content">
   347→            {msg.content && (
   348→              <div className="message-detail__text">
   349→                <ReactMarkdown>{msg.content}</ReactMarkdown>
   350→              </div>
   351→            )}
   352→            {hasItems && (
   353→              <div className="detail-items">
   354→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
   355→                {msg.items.map((item, idx) => (
   356→                  <DetailItem
   357→                    key={`${idx}-${item.item_type}-${item.agent_id || item.tool_name}`}
   358→                    ref={idx === selectedItem ? scrollRef : undefined}
   359→                    item={item}
   360→                    index={idx}
   361→                    isSelected={idx === selectedItem}
   362→                    isExpanded={expandedItems.has(idx)}
   363→                    isAgentActive={
   364→                      panelStack.length > 0 &&
   365→                      panelStack[0].item.agent_id === item.agent_id &&
   366→                      !!item.agent_id
   367→                    }
   368→                    onToggle={handleItemClick}
   369→                    onToggleExpand={toggleItem}
   370→                    onSelect={setSelectedItem}
   371→                  />
   372→                ))}
   373→              </div>
   374→            )}
   375→            {ongoing && (
   376→              <div className="message-detail__ongoing">
   377→                <OngoingDots />
   378→              </div>
   379→            )}
   380→          </div>
   381→        </div>
   382→      </div>
   383→
   384→      {panelStack.map((entry, depth) => {
   385→        const colWidth = columnWidths[depth + 1];
   386→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
   387→        const isFocused = focusedColumn === depth + 1;
   388→
   389→        return (
   390→          <PanelColumn
   391→            key={entry.key}
   392→            entry={entry}
   393→            depth={depth}
   394→            style={widthStyle}
   395→            isFocused={isFocused}
   396→            panelStack={panelStack}
   397→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
   398→            onBackToList={() => backToListAt(depth)}
   399→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
   400→            onClose={() => closeAt(depth)}
   401→            onResize={(w) => setColumnWidth(depth, w)}
   402→            onFocus={() => setFocusedColumn(depth + 1)}
   403→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
   404→          />
   405→        );
   406→      })}
   407→    </div>
   408→  );
   409→}
   410→
   411→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
   412→
   413→interface PanelColumnProps {
   414→  entry: PanelEntry;
   415→  depth: number;
   416→  style?: React.CSSProperties;
   417→  isFocused: boolean;
   418→  panelStack: PanelEntry[];
   419→  onOpenDetail: (msg: DisplayMessage) => void;
   420→  onBackToList: () => void;
   421→  onOpenSubagent: (item: DisplayItem) => void;
   422→  onClose: () => void;
   423→  onResize: (width: number) => void;
   424→  onFocus: () => void;
   425→  onRegisterNav: (nav: ColumnNav | null) => void;
   426→}
   427→
   428→function PanelColumn({
   429→  entry,
   430→  depth,
   431→  style,
   432→  isFocused,
   433→  panelStack,
   434→  onOpenDetail,
   435→  onBackToList,
   436→  onOpenSubagent,
   437→  onClose,
   438→  onResize,
   439→  onFocus,
   440→  onRegisterNav,
   441→}: PanelColumnProps) {
   442→  return (
   443→    <>
   444→      <ResizeHandle onResize={onResize} />
   445→      {entry.kind === "agent-list" ? (
   446→        <AgentListColumn
   447→          item={entry.item}
   448→          style={style}
   449→          isFocused={isFocused}
   450→          onOpenDetail={onOpenDetail}
   451→          onClose={onClose}
   452→          onFocus={onFocus}
   453→          onRegisterNav={onRegisterNav}
   454→        />
   455→      ) : (
   456→        <AgentDetailColumn
   457→          item={entry.item}
   458→          msg={entry.msg}
   459→          style={style}
   460→          isFocused={isFocused}
   461→          depth={depth}
   462→          panelStack={panelStack}
   463→          onOpenSubagent={onOpenSubagent}
   464→          onBack={onBackToList}
   465→          onClose={onClose}
   466→          onFocus={onFocus}
   467→          onRegisterNav={onRegisterNav}
   468→        />
   469→      )}
   470→    </>
   471→  );
   472→}
   473→
   474→/* ─── AgentListColumn: shows agent header + message list ─── */
   475→
   476→interface AgentListColumnProps {
   477→  item: DisplayItem;
   478→  style?: React.CSSProperties;
   479→  isFocused: boolean;
   480→  onOpenDetail: (msg: DisplayMessage) => void;
   481→  onClose: () => void;
   482→  onFocus: () => void;
   483→  onRegisterNav: (nav: ColumnNav | null) => void;
   484→}
   485→
   486→function AgentListColumn({
   487→  item,
   488→  style,
   489→  isFocused,
   490→  onOpenDetail,
   491→  onClose,
   492→  onFocus,
   493→  onRegisterNav,
   494→}: AgentListColumnProps) {
   495→  const messages = item.subagent_messages;
   496→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
   497→  const {
   498→    set: expandedSet,
   499→    toggle: toggleMsg,
   500→    addAll: expandAllMsgs,
   501→    clear: clearMsgs,
   502→  } = useToggleSet();
   503→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
   504→  const selectedRef = useScrollToSelected(selectedMsg);
   505→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
   506→
   507→  const handleClick = useCallback(
   508→    (index: number) => {
   509→      onFocus();
   510→      if (selectedMsg === index) {
   511→        toggleMsg(index);
   512→      } else {
   513→        setSelectedMsg(index);
   514→      }
   515→    },
   516→    [selectedMsg, toggleMsg, onFocus],
   517→  );
   518→
   519→  // Expose navigation to parent via callback ref
   520→  const navRef = useRef<ColumnNav>({
   521→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
   522→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
   523→    toggle: () => toggleMsg(selectedMsg),
   524→    enter: () => {
   525→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
   526→    },
   527→    itemCount: () => messages.length,
   528→    expandAll: () => expandAllMsgs(messages.map((_, i) => i)),
   529→    collapseAll: () => clearMsgs(),
   530→  });
   531→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
   532→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
   533→  navRef.current.toggle = () => toggleMsg(selectedMsg);
   534→  navRef.current.enter = () => {
   535→    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
   536→  };
   537→  navRef.current.itemCount = () => messages.length;
   538→  navRef.current.expandAll = () => expandAllMsgs(messages.map((_, i) => i));
   539→  navRef.current.collapseAll = () => clearMsgs();
   540→
   541→  // Register/unregister nav on mount/unmount
   542→  useLayoutEffect(() => {
   543→    onRegisterNav(navRef.current);
   544→    return () => onRegisterNav(null);
   545→  }, [onRegisterNav]);
   546→
   547→  return (
   548→    <div
   549→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
   550→      style={
   551→        {
   552→          ...(panelColor ? { background: `${panelColor}08` } : {}),
   553→          ...style,
   554→        } as React.CSSProperties
   555→      }
   556→      onClick={onFocus}
   557→    >
   558→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
   559→      <div className="agent-panel__content">
   560→        <div className="agent-panel__list" ref={listRef}>
   561→          {messages.map((msg, i) => {
   562→            if (msg.role === "compact") {
   563→              return (
   564→                <div key={`${i}-compact`} className="compact-separator">
   565→                  <div className="compact-separator__line">
   566→                    <span className="compact-separator__rule" />
   567→                    <span>{msg.content}</span>
   568→                    <span className="compact-separator__rule" />
   569→                  </div>
   570→                </div>
   571→              );
   572→            }
   573→            const isSelected = i === selectedMsg;
   574→            const isExpanded = expandedSet.has(i);
   575→            const isLast = i === messages.length - 1;
   576→            return (
   577→              <MessageItem
   578→                key={`${i}-${msg.role}-${msg.timestamp}`}
   579→                ref={isSelected ? selectedRef : undefined}
   580→                message={msg}
   581→                index={i}
   582→                isSelected={isSelected}
   583→                isExpanded={isExpanded}
   584→                isOngoing={isLast && item.subagent_ongoing}
   585→                onClick={handleClick}
   586→                onOpenDetail={(idx) => onOpenDetail(messages[idx])}
   587→              />
   588→            );
   589→          })}
   590→        </div>
   591→      </div>
   592→    </div>
   593→  );
   594→}
   595→
   596→/* ─── AgentDetailColumn: shows a single message's detail items ─── */
   597→
   598→interface AgentDetailColumnProps {
   599→  item: DisplayItem;
   600→  msg: DisplayMessage;
   601→  style?: React.CSSProperties;
   602→  isFocused: boolean;
   603→  depth: number;
   604→  panelStack: PanelEntry[];
   605→  onOpenSubagent: (item: DisplayItem) => void;
   606→  onBack: () => void;
   607→  onClose: () => void;
   608→  onFocus: () => void;
   609→  onRegisterNav: (nav: ColumnNav | null) => void;
   610→}
   611→
   612→function AgentDetailColumn({
   613→  item,
   614→  msg,
   615→  style,
   616→  isFocused,
   617→  depth,
   618→  panelStack,
   619→  onOpenSubagent,
   620→  onBack,
   621→  onClose,
   622→  onFocus,
   623→  onRegisterNav,
   624→}: AgentDetailColumnProps) {
   625→  const {
   626→    set: expandedItems,
   627→    toggle: toggleItem,
   628→    addAll: expandAllDetailItems,
   629→    clear: clearDetailItems,
   630→  } = useToggleSet();
   631→  const [selectedItem, setSelectedItem] = useState(0);
   632→  const scrollRef = useScrollToSelected(selectedItem);
   633→  const detailBodyRef = useAutoScroll<HTMLDivElement>(msg.items.length);
   634→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
   635→
   636→  const model = msg.model ? shortModel(msg.model) : "";
   637→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
   638→  const time = formatExactTime(msg.timestamp);
   639→  const hasItems = msg.items.length > 0;
   640→
   641→  // Check if a deeper panel is open for a given agent_id
   642→  const activeAgentId = depth + 1 < panelStack.length ? panelStack[depth + 1].item.agent_id : null;
   643→
   644→  const handleItemClick = (index: number, clickedItem: DisplayItem) => {
   645→    onFocus();
   646→    setSelectedItem(index);
   647→    if (clickedItem.subagent_messages.length > 0) {
   648→      onOpenSubagent(clickedItem);
   649→    } else {
   650→      toggleItem(index);
   651→    }
   652→  };
   653→
   654→  // Expose navigation to parent via callback ref
   655→  const navRef = useRef<ColumnNav>({
   656→    moveUp: () => {},
   657→    moveDown: () => {},
   658→    toggle: () => {},
   659→    enter: () => {},
   660→    itemCount: () => msg.items.length,
   661→    expandAll: () => expandAllDetailItems(msg.items.map((_, i) => i)),
   662→    collapseAll: () => clearDetailItems(),
   663→  });
   664→  navRef.current.moveUp = () => setSelectedItem((i) => Math.max(i - 1, 0));
   665→  navRef.current.moveDown = () => setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
   666→  navRef.current.toggle = () => {
   667→    const it = msg.items[selectedItem];
   668→    if (it) handleItemClick(selectedItem, it);
   669→  };
   670→  navRef.current.enter = () => {
   671→    const it = msg.items[selectedItem];
   672→    if (it && it.subagent_messages.length > 0) {
   673→      onOpenSubagent(it);
   674→    } else if (it) {
   675→      toggleItem(selectedItem);
   676→    }
   677→  };
   678→  navRef.current.itemCount = () => msg.items.length;
   679→  navRef.current.expandAll = () => expandAllDetailItems(msg.items.map((_, i) => i));
   680→  navRef.current.collapseAll = () => clearDetailItems();
   681→
   682→  useLayoutEffect(() => {
   683→    onRegisterNav(navRef.current);
   684→    return () => onRegisterNav(null);
   685→  }, [onRegisterNav]);
   686→
   687→  return (
   688→    <div
   689→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
   690→      style={
   691→        {
   692→          ...(panelColor ? { background: `${panelColor}08` } : {}),
   693→          ...style,
   694→        } as React.CSSProperties
   695→      }
   696→      onClick={onFocus}
   697→    >
   698→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
   699→      <div className="agent-panel__content">
   700→        <div className="message-detail__header" style={{ borderBottom: "1px solid var(--border)" }}>
   701→          <BackButton onClick={onBack} />
   702→          <span className="message-detail__title">
   703→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
   704→          </span>
   705→          {model && (
   706→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
   707→          )}
   708→          <span className="message-detail__meta">
   709→            {time}
   710→            {msg.tokens_raw > 0 && (
   711→              <>
   712→                {" "}
   713→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
   714→              </>
   715→            )}
   716→          </span>
   717→        </div>
   718→        <div className="message-detail__body" ref={detailBodyRef}>
   719→          <div className="message-detail__content">
   720→            {msg.content && (
   721→              <div className="message-detail__text">
   722→                <ReactMarkdown>{msg.content}</ReactMarkdown>
   723→              </div>
   724→            )}
   725→            {hasItems && (
   726→              <div className="detail-items">
   727→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
   728→                {msg.items.map((di, idx) => (
   729→                  <DetailItem
   730→                    key={`${idx}-${item.item_type}-${item.agent_id || item.tool_name}`}
   731→                    ref={idx === selectedItem ? scrollRef : undefined}
   732→                    item={di}
   733→                    index={idx}
   734→                    isSelected={idx === selectedItem}
   735→                    isExpanded={expandedItems.has(idx)}
   736→                    isAgentActive={activeAgentId === di.agent_id && !!di.agent_id}
   737→                    onToggle={handleItemClick}
   738→                    onToggleExpand={toggleItem}
   739→                    onSelect={setSelectedItem}
   740→                  />
   741→                ))}
   742→              </div>
   743→            )}
   744→            {item.subagent_ongoing && (
   745→              <div className="message-detail__ongoing">
   746→                <OngoingDots />
   747→              </div>
   748→            )}
   749→          </div>
   750→        </div>
   751→      </div>
   752→    </div>
   753→  );
   754→}
   755→
   756→/* ─── Shared agent panel header ─── */
   757→
   758→function AgentPanelHeader({
   759→  item,
   760→  panelColor,
   761→  onClose,
   762→}: {
   763→  item: DisplayItem;
   764→  panelColor?: string;
   765→  onClose: () => void;
   766→}) {
   767→  return (
   768→    <div
   769→      className="agent-panel__header"
   770→      style={panelColor ? { background: `${panelColor}10` } : undefined}
   771→    >
   772→      <button className="agent-panel__close" onClick={onClose}>
   773→        <IoMdCloseCircle className="icon--close" />
   774→      </button>
   775→      <span className="agent-panel__icon">
   776→        <ClaudeIcon />
   777→      </span>
   778→      <span className="agent-panel__type" style={panelColor ? { color: panelColor } : undefined}>
   779→        {item.subagent_type || item.tool_name || "Subagent"}
   780→      </span>
   781→      {(item.subagent_desc || item.tool_summary) && (
   782→        <span className="agent-panel__desc">{item.subagent_desc || item.tool_summary}</span>
   783→      )}
   784→      {item.agent_id && <span className="agent-panel__id">{item.agent_id}</span>}
   785→      <span className="agent-panel__stats">
   786→        {item.duration_ms > 0 && <span>{formatDuration(item.duration_ms)}</span>}
   787→      </span>
   788→    </div>
   789→  );
   790→}
